import { BaseActivePersona } from "../../base.ts";
import type { AuditRule, StrategicFinding, AuditFinding, HealingResult, ProjectContext } from "../../base.ts";

/**
 * 🔮 Dr. Mantra — PhD in Type Purity & Strictness (TypeScript)
 * Generated by Sovereign Forge.
 */
export class MantraPersona extends BaseActivePersona {
    constructor(projectRoot: string | undefined = undefined) {
        super(projectRoot);
        this.id = "mantra";
        this.name = "Mantra";
        this.emoji = "🔮";
        this.role = "PhD Type System Guardian";
        this.phd_identity = "Type Purity & Strictness (TypeScript)";
        this.stack = "Bun";
        this.healingPrompt = "Fix the following code style or consistency violation. Enforce naming conventions, formatting rules, and coding standards. Return ONLY the corrected code or a specific diff.";
    }

    override async execute(context: ProjectContext): Promise<(AuditFinding | StrategicFinding)[]> {
        this.setContext(context);
        if (this.healingPrompt) {
            const { findings } = await this.auditAndHeal();
            return findings;
        }
        const findings = await this.performAudit();
        return findings;
    }

    override getAuditRules(): { extensions: string[]; rules: AuditRule[] } {
        return {
            extensions: [".ts",".js"],
            rules: [
          {
                    "regex": ":\\s*any\\b",
                    "issue": "Impureza: Tipagem \"any\" destrói a segurança do type system.",
                    "severity": "high"
          },
          {
                    "regex": "as\\s+any\\b",
                    "issue": "Escape: Type assertion \"as any\" — força passagem sem verificação.",
                    "severity": "high"
          },
          {
                    "regex": "@ts-ignore",
                    "issue": "Supressão: @ts-ignore silencia erro do compilador.",
                    "severity": "critical"
          },
          {
                    "regex": "@ts-nocheck",
                    "issue": "Abandono: @ts-nocheck desativa verificação do arquivo inteiro.",
                    "severity": "critical"
          },
          {
                    "regex": "Record<string,\\s*any>",
                    "issue": "Opacidade: Record<string, any> — dicionário sem tipagem de valor.",
                    "severity": "medium"
          }
]
        };
    }

    public override async performAudit(): Promise<AuditFinding[]> {
        this.startMetrics();
        
        const allFindings: AuditFinding[] = [];
        const files = Object.keys(this.contextData);
        
        for (const file of files) {
            const results = await this.delegateAuditToHub(file);
            // Inject file path if hub didn't (hub uses 'embedded_content' for raw content)
            results.forEach(f => {
                if (f.file === "embedded_content") f.file = file;
                allFindings.push(f);
            });
        }
        
        this.endMetrics(allFindings.length);
        return allFindings;
    }

    public override async reasonAboutObjective(objective: string, file: string, context: string): Promise<StrategicFinding | null> {
        return await super.reasonAboutObjective(objective, file, context);
    }

    override selfDiagnostic(): any {
        return { status: "Soberano", score: 100, details: "Módulo Mantra operando com paridade total via Forge." };
    }

    override getSystemPrompt(): string {
        return `Você é o Dr. Mantra, PhD em Type Purity & Strictness (TypeScript). Sua missão é garantir a excelência via governança PhD.`;
    }
}
